// src/providers/theme-provider.tsx
"use client"

import * as React from "react"
import { ThemeProvider as NextThemesProvider } from "next-themes"
import { type ThemeProviderProps } from "next-themes"

export function ThemeProvider({ children, ...props }: ThemeProviderProps) {
  return <NextThemesProvider {...props}>{children}</NextThemesProvider>
}


// src/app/layout.tsx
import { AuthProvider } from '@/contexts/AuthContext';
import { CompanyProvider } from '@/contexts/CompanyContext';
import { MessagingProvider } from '@/contexts/messaging/MessagingContext';
import { ThemeProvider } from '@/providers/theme-provider';
import { QueryProvider } from '@/providers/query-provider';
import { Toaster } from 'sonner';
import { PresenceProvider } from '@/contexts/PresenceContext';
import { CallingProvider } from '@/contexts/CallingContext';
import { CallNotifications } from '@/components/messaging/CallNotification';
import { MessagingDrawer } from '@/components/messaging/MessagingDrawer';
import { MessagingTrigger } from '@/components/messaging/MessagingTrigger';
import './globals.css';

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <html lang="en" suppressHydrationWarning>
      <body>
        <ThemeProvider
          attribute="class"
          defaultTheme="system"
          enableSystem
          disableTransitionOnChange
        >
          {/* ... providers ... */}
        </ThemeProvider>
      </body>
    </html>
  );
}

      Current ThemeProvider uses attribute="class" - need to change to attribute="data-theme" for VO themes


