type VOTheme = 'neon' | 'zen' | 'obsidian' | 'paper' | 'system';

interface UseVOThemeReturn {
  theme: VOTheme | undefined;
  setTheme: (theme: VOTheme) => void;
  resolvedTheme: VOTheme | undefined;
  themes: VOTheme[];
  systemTheme: 'light' | 'dark' | undefined;
}
